    19	/// 对象系统基类
    20	struct alignas(ptrdiff_t) Obj
    21	{
    22	  struct Mgr;
    23	  struct Walked;
    24	
    25	  using Mark = void (*)(Obj* obj);
    26	
    27	  Obj() = default;
    28	  virtual ~Obj() = default;
    29	
    30	  template<typename T>
    31	  T* dcst()
    32	  {
    33	    return dynamic_cast<T*>(this);
    34	  }
    35	
    36	  template<typename T>
    37	  T* dcst() const
    38	  {
    39	    return dynamic_cast<T*>(this);
    40	  }
    41	
    42	  template<typename T>
    43	  T* scst()
    44	  {
    45	    return static_cast<T*>(this);
    46	  }
    47	
    48	  template<typename T>
    49	  T* scst() const
    50	  {
    51	    return static_cast<T*>(this);
    52	  }
    53	
    54	  template<typename T>
    55	  T& rcst()
    56	  {
    57	    return *reinterpret_cast<T*>(this);
    58	  }
    59	
    60	  template<typename T>
    61	  T& rcst() const
    62	  {
    63	    return *reinterpret_cast<T*>(this);
    64	  }
    65	
    66	  void* any{ nullptr }; /// 留给遍历器存放任意数据
    67	
    68	  template<typename T>
    69	  T* any_as()
    70	  {
    71	    return reinterpret_cast<T*>(any);
    72	  }
    73	
    74	  template<typename T>
    75	  T* any_as() const
    76	  {
    77	    return reinterpret_cast<T*>(any);
    78	  }
