    80	private:
    81	  Obj(Obj* next)
    82	    : __next__(next)
    83	  {
    84	  }
    85	
    86	  Obj(const Obj&) = delete;
    87	  Obj(Obj&&) = delete;
    88	  void operator=(const Obj&) = delete;
    89	  void operator=(Obj&&) = delete;
    90	
    91	  Obj* __next__{ nullptr }; /// 环形指针，低3位由于对齐要求必为0，用作标记
    92	
    93	  virtual void __mark__(Mark mark) = 0; /// 标记对象
    94	};
    95	
    96	/// 对象管理器
    97	struct Obj::Mgr : Obj
    98	{
    99	  Mgr()
   100	    : Obj(this)
   101	  {
   102	  }
   103	
   104	  template<typename T,
   105	           typename... Args,
   106	           typename = std::enable_if_t<std::is_convertible_v<T*, Obj*>>>
   107	  T* make(Args... args)
   108	  {
   109	    auto obj = new T(args...);
   110	    obj->__next__ = __next__, __next__ = obj;
   111	    return obj;
   112	  }
   113	
   114	  Obj* mRoot{ nullptr }; /// 根对象
