   120	private:
   121	  void __mark__(Mark mark) override;
   122	
   123	  static bool gc_marked(const Obj* obj)
   124	  {
   125	    return reinterpret_cast<uintptr_t>(obj->__next__) & uintptr_t(0b1);
   126	  }
   127	
   128	  static void gc_unmark(Obj* obj)
   129	  {
   130	    reinterpret_cast<uintptr_t&>(obj->__next__) &= ~uintptr_t(0b1);
   131	  }
   132	
   133	  static void gc_mark(Obj* obj)
   134	  {
   135	    reinterpret_cast<uintptr_t&>(obj->__next__) |= uintptr_t(0b1);
   136	  }
   137	
   138	  static void gc_mark_dfs(Obj* obj);
   139	};
